def detect_policy_violations(agent_session):
    violations = 0
    for step in agent_session.steps:
        if step.tool_calls:
            for tool_call in step.tool_calls:
                # Check for missing enterprise policy validation
                if 'policy_check' not in tool_call.metadata:
                    violations += 1
                    print(f'❌ Unvalidated tool call: {tool_call.name}')
    return violations > 0

import re
from datetime import datetime, timedelta

def audit_grounding_consistency(messages):
    bing_sources = []
    file_sources = []

    for msg in messages:
        if msg.role == 'system' and 'bing' in msg.content.lower():
            # Extract Bing search timestamp
            timestamp_match = re.search(r'(\d{4}-\d{2}-\d{2})', msg.content)
            if timestamp_match:
                bing_sources.append(datetime.fromisoformat(timestamp_match.group(1)))

    stale_data = any((datetime.now() - source).days > 1 for source in bing_sources)
    return {'stale_bing': stale_data, 'source_conflict': len(bing_sources) > 0 and len(file_sources) > 0}

